import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"龙书文拔拳术","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/龙书文拔拳术.md","filePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/龙书文拔拳术.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/肉搏类/龙书文拔拳术.md"};function p(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"龙书文拔拳术",tabindex:"-1"},[s("龙书文拔拳术 "),e("a",{class:"header-anchor",href:"#龙书文拔拳术","aria-label":'Permalink to "龙书文拔拳术"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),o('<h1 id="龙书文拔拳术-1" tabindex="-1">龙书文拔拳术 <a class="header-anchor" href="#龙书文拔拳术-1" aria-label="Permalink to &quot;龙书文拔拳术&quot;">​</a></h1><p>拔拳术<br> 技艺<br> 价格：D+500<br> 特异本质<br> 这是“不受拘束之士”龙书文的特技，将双手插在口袋隐藏拳路，利用腰力快速出拳的拳法“拔拳术”。</p><p>前提：穿着具有口袋，或者至少可以隐藏双手的衣服。</p><p>对战时，人物需将双手插于口袋内，这种架势看似漏洞百出，但实际上早已做好随时应敌的准备，手并不是单纯的从口袋中抽出，而是是利用腰部的力量从口袋中甩出，这使得手早已在口袋内就完成加速，这种快速出拳的攻击可以使得对方无法看清你的拳路，但反过来，一旦高速的优势不在，攻击被人预测，这种无法变招的攻击则很难起到真正的效果。</p><p>在你的回合开始时，一回合一次，以一个花招动作将双手插在口袋中，那在本轮进行一次肉搏攻击时，你可以立刻进行一次【拔拳术】检定，这是一个纯敏捷属性检定不计入附加成功，也不计入任何额外加值，无法因其他效果调整成功数。然后本次肉搏攻击获得等同于该检定的成功数的速度加值。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
